  1→// ── Shared channel RPC wrappers and validation ────────────────
  2→//
  3→// Used by page-channels.js and onboarding-view.js.
  4→
  5→import { get as getGon } from "./gon.js";
  6→import { sendRpc } from "./helpers.js";
  7→
  8→export var MATRIX_DOCS_URL = "https://docs.moltis.org/matrix.html";
  9→export var MATRIX_DEFAULT_HOMESERVER = "https://matrix.org";
 10→export var MATRIX_ENCRYPTION_GUIDANCE =
 11→	"Encrypted Matrix chats require Password auth. Access token auth can connect for plain Matrix traffic, but it reuses an existing Matrix session without that device's private encryption keys, so Moltis cannot reliably decrypt encrypted chats. Use Password so Moltis creates and persists its own Matrix device keys, then finish Element verification in the same Matrix DM or room by sending `verify yes`, `verify no`, `verify show`, or `verify cancel` as normal chat messages.";
 12→export function matrixAuthModeGuidance(authMode) {
 13→	return normalizeMatrixAuthMode(authMode) === "password"
 14→		? "Required for encrypted Matrix chats. Moltis logs in as its own Matrix device and stores the device's encryption keys locally."
 15→		: "Does not support encrypted Matrix chats. Access tokens authenticate an existing Matrix session, but they do not transfer that device's private encryption keys into Moltis.";
 16→}
 17→export function channelStorageNote() {
 18→	var dbPath = String(getGon("channel_storage_db_path") || "").trim();
 19→	if (dbPath) {
 20→		return `Channels added or edited in the web UI are stored in Moltis's internal database (${dbPath}). They are not written back to moltis.toml. The channel picker itself comes from [channels].offered in moltis.toml, so reload this page after editing that list.`;
 21→	}
 22→	return "Channels added or edited in the web UI are stored in Moltis's internal database (moltis.db). They are not written back to moltis.toml. The channel picker itself comes from [channels].offered in moltis.toml, so reload this page after editing that list.";
 23→}
 24→
 25→/**
 26→ * Validate required channel fields before submission.
 27→ * @param {string} type - channel type
 28→ * @param {string} accountId - account identifier
 29→ * @param {string} credential - primary credential (token or app password)
 30→ * @param {{ matrixAuthMode?: string, matrixUserId?: string }} [options]
 31→ * @returns {{ valid: true } | { valid: false, error: string }}
 32→ */
 33→export function validateChannelFields(type, accountId, credential, options = {}) {
 34→	if (!accountId.trim()) {
 35→		return { valid: false, error: "Account ID is required." };
 36→	}
 37→	if (!credential.trim()) {
 38→		if (type === "matrix") {
 39→			return { valid: false, error: matrixCredentialError(options.matrixAuthMode) };
 40→		}
 41→		return {
 42→			valid: false,
 43→			error: type === "msteams" ? "App password is required." : "Bot token is required.",
 44→		};
 45→	}
 46→	if (
 47→		type === "matrix" &&
 48→		normalizeMatrixAuthMode(options.matrixAuthMode) === "password" &&
 49→		!String(options.matrixUserId || "").trim()
 50→	) {
 51→		return { valid: false, error: "Matrix user ID is required for password login." };
 52→	}
 53→	return { valid: true };
 54→}
 55→
 56→export function normalizeMatrixAuthMode(authMode) {
 57→	return authMode === "password" ? "password" : "access_token";
 58→}
 59→
 60→export function normalizeMatrixOwnershipMode(mode) {
 61→	return mode === "moltis_owned" ? "moltis_owned" : "user_managed";
 62→}
 63→
 64→export function matrixOwnershipModeGuidance(authMode, ownershipMode) {
 65→	if (normalizeMatrixAuthMode(authMode) !== "password") {
 66→		return "Access token auth always stays user-managed because it reuses an existing Matrix session instead of giving Moltis full control of the account's encryption state.";
 67→	}
 68→	return normalizeMatrixOwnershipMode(ownershipMode) === "moltis_owned"
 69→		? "Recommended for dedicated bot accounts. Moltis bootstraps cross-signing and recovery for this account so it can verify its own Matrix device automatically."
 70→		: "Use this if you want to open the same bot account in Element or another Matrix client yourself. Moltis will not try to take over the account's cross-signing or recovery state.";
 71→}
 72→
 73→export function matrixCredentialLabel(authMode) {
 74→	return normalizeMatrixAuthMode(authMode) === "password" ? "Password" : "Access Token";
 75→}
 76→
 77→export function matrixCredentialPlaceholder(authMode) {
 78→	return normalizeMatrixAuthMode(authMode) === "password" ? "Account password" : "syt_...";
 79→}
 80→
 81→export function matrixCredentialError(authMode) {
 82→	return normalizeMatrixAuthMode(authMode) === "password" ? "Password is required." : "Access token is required.";
 83→}
 84→
 85→function randomSuffix(length) {
 86→	if (typeof window !== "undefined" && window.crypto?.getRandomValues) {
 87→		var bytes = new Uint8Array(length);
 88→		window.crypto.getRandomValues(bytes);
 89→		return Array.from(bytes, (byte) => (byte % 36).toString(36)).join("");
 90→	}
 91→	var value = "";
 92→	while (value.length < length) {
 93→		value += Math.floor(Math.random() * 36).toString(36);
 94→	}
 95→	return value.slice(0, length);
 96→}
 97→
 98→function slugifyMatrixAccountPart(value) {
 99→	return String(value || "")
100→		.toLowerCase()
101→		.trim()
102→		.replace(/^@/, "")
103→		.replace(/[^a-z0-9]+/g, "-")
104→		.replace(/-+/g, "-")
105→		.replace(/^-|-$/g, "");
106→}
107→
108→function matrixHomeserverHost(homeserver) {
109→	var raw = String(homeserver || "").trim();
110→	if (!raw) return "";
111→	if (!/^https?:\/\//i.test(raw)) raw = `https://${raw}`;
112→	try {
113→		return new URL(raw).hostname;
114→	} catch (_error) {
115→		return "";
116→	}
117→}
118→
119→/**
120→ * Generate a local Matrix account identifier for Moltis.
121→ * Prefer the Matrix user ID when present, otherwise derive from homeserver.
122→ * @param {{ userId?: string, homeserver?: string }} options
123→ * @returns {string}
124→ */
125→export function deriveMatrixAccountId(options = {}) {
126→	var userSlug = slugifyMatrixAccountPart(options.userId);
127→	if (userSlug) return userSlug.slice(0, 80);
128→
129→	var hostSlug = slugifyMatrixAccountPart(matrixHomeserverHost(options.homeserver));
130→	var base = hostSlug || "matrix";
131→	return `${base}-${randomSuffix(6)}`.slice(0, 80);
132→}
133→
134→/**
135→ * Normalize Matrix OTP cooldown input to a positive integer.
136→ * @param {string | number | null | undefined} value
137→ * @param {number} [fallback]
138→ * @returns {number}
139→ */
140→export function normalizeMatrixOtpCooldown(value, fallback = 300) {
141→	var parsed = Number.parseInt(String(value || ""), 10);
142→	return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
143→}
144→
145→/**
146→ * Parse an optional advanced channel config JSON object.
147→ * @param {string | null | undefined} text
148→ * @returns {{ ok: true, value: Record<string, unknown> } | { ok: false, error: string }}
149→ */
150→export function parseChannelConfigPatch(text) {
151→	var raw = String(text || "").trim();
152→	if (!raw) return { ok: true, value: {} };
153→	try {
154→		var value = JSON.parse(raw);
155→		if (!(value && typeof value === "object" && !Array.isArray(value))) {
156→			return { ok: false, error: "Advanced config must be a JSON object." };
157→		}
158→		return { ok: true, value };
159→	} catch (error) {
160→		var message = error instanceof Error ? error.message : String(error || "unknown error");
161→		return { ok: false, error: `Advanced config JSON is invalid: ${message}` };
162→	}
163→}
164→
165→/**
166→ * Add a new channel (e.g. Telegram bot).
167→ * @param {string} type - channel type, e.g. "telegram"
168→ * @param {string} accountId - bot username / account identifier
169→ * @param {object} config - channel-specific config (token, dm_policy, etc.)
170→ */
171→export function addChannel(type, accountId, config) {
172→	return sendRpc("channels.add", { type, account_id: accountId, config });
173→}
174→
175→/**
176→ * Fetch the current status of all configured channels.
177→ * Resolves with the RPC response; payload has `{ channels: [] }`.
178→ */
179→export function fetchChannelStatus() {
180→	return sendRpc("channels.status", {});
181→}
182→
183→/**
184→ * Default base URL for Teams webhook endpoints.
185→ * Prefer a discovered public URL when available, otherwise fall back to the
186→ * current page origin.
187→ */
188→export function defaultTeamsBaseUrl(preferredPublicUrl) {
189→	var preferred = (preferredPublicUrl || "").trim();
190→	if (preferred) return preferred;
191→	if (typeof window === "undefined") return "";
192→	return window.location?.origin || "";
193→}
194→
195→/**
196→ * Normalise a user-provided base URL into `protocol://host`.
197→ */
198→export function normalizeBaseUrlForWebhook(baseUrl) {
199→	var raw = (baseUrl || "").trim();
200→	if (!raw) raw = defaultTeamsBaseUrl();
201→	if (!raw) return "";
202→	if (!/^https?:\/\//i.test(raw)) raw = `https://${raw}`;
203→	try {
204→		var parsed = new URL(raw);
205→		return `${parsed.protocol}//${parsed.host}`;
206→	} catch (_e) {
207→		return "";
208→	}
209→}
210→
211→/**
212→ * Generate a random 48-hex-char webhook secret.
213→ */
214→export function generateWebhookSecretHex() {
215→	if (typeof window !== "undefined" && window.crypto?.getRandomValues) {
216→		var bytes = new Uint8Array(24);
217→		window.crypto.getRandomValues(bytes);
218→		return Array.from(bytes, (b) => b.toString(16).padStart(2, "0")).join("");
219→	}
220→	var value = "";
221→	while (value.length < 48) {
222→		value += Math.floor(Math.random() * 16).toString(16);
223→	}
224→	return value.slice(0, 48);
225→}
226→
227→/**
228→ * Build the full Teams messaging endpoint URL.
229→ */
230→export function buildTeamsEndpoint(baseUrl, accountId, webhookSecret) {
231→	var normalizedBase = normalizeBaseUrlForWebhook(baseUrl);
232→	var account = (accountId || "").trim();
233→	var secret = (webhookSecret || "").trim();
234→	if (!(normalizedBase && account && secret)) return "";
235→	return `${normalizedBase}/api/channels/msteams/${encodeURIComponent(account)}/webhook?secret=${encodeURIComponent(secret)}`;
236→}
