  1→// ── Channels page (Preact + HTM + Signals) ──────────────────
  2→
  3→import { signal, useSignal } from "@preact/signals";
  4→import { html } from "htm/preact";
  5→import { render } from "preact";
  6→import { useEffect, useState } from "preact/hooks";
  7→import {
  8→	addChannel,
  9→	buildTeamsEndpoint,
 10→	channelStorageNote,
 11→	defaultTeamsBaseUrl,
 12→	deriveMatrixAccountId,
 13→	fetchChannelStatus,
 14→	generateWebhookSecretHex,
 15→	MATRIX_DEFAULT_HOMESERVER,
 16→	MATRIX_DOCS_URL,
 17→	MATRIX_ENCRYPTION_GUIDANCE,
 18→	matrixAuthModeGuidance,
 19→	matrixCredentialLabel,
 20→	matrixCredentialPlaceholder,
 21→	matrixOwnershipModeGuidance,
 22→	normalizeMatrixAuthMode,
 23→	normalizeMatrixOtpCooldown,
 24→	normalizeMatrixOwnershipMode,
 25→	parseChannelConfigPatch,
 26→	validateChannelFields,
 27→} from "./channel-utils.js";
 28→import { onEvent } from "./events.js";
 29→import { get as getGon } from "./gon.js";
 30→import { sendRpc } from "./helpers.js";
 31→import { updateNavCount } from "./nav-counts.js";
 32→import { connected } from "./signals.js";
 33→import * as S from "./state.js";
 34→import { models as modelsSig } from "./stores/model-store.js";
 35→import { ConfirmDialog, Modal, ModelSelect, requestConfirm, showToast } from "./ui.js";
 36→
 37→var channels = signal([]);
 38→
 39→export function prefetchChannels() {
 40→	return fetchChannelStatus().then((res) => {
 41→		if (res?.ok) {
 42→			var ch = res.payload?.channels || [];
 43→			channels.value = ch;
 44→			S.setCachedChannels(ch);
 45→		}
 46→	});
 47→}
 48→var senders = signal([]);
 49→var activeTab = signal("channels");
 50→var showAddTelegram = signal(false);
 51→var showAddTeams = signal(false);
 52→var showAddDiscord = signal(false);
 53→var showAddWhatsApp = signal(false);
 54→var showAddSlack = signal(false);
 55→var showAddMatrix = signal(false);
 56→var editingChannel = signal(null);
 57→var sendersAccount = signal("");
 58→
 59→// Track WhatsApp pairing state (updated by WebSocket events).
 60→var waQrData = signal(null);
 61→var waQrSvg = signal(null);
 62→var waPairingAccountId = signal(null);
 63→var waPairingError = signal(null);
 64→
 65→function channelType(type) {
 66→	return type || "telegram";
 67→}
 68→
 69→function channelLabel(type) {
 70→	var t = channelType(type);
 71→	if (t === "msteams") return "Microsoft Teams";
 72→	if (t === "discord") return "Discord";
 73→	if (t === "whatsapp") return "WhatsApp";
 74→	if (t === "slack") return "Slack";
 75→	if (t === "matrix") return "Matrix";
 76→	return "Telegram";
 77→}
 78→
 79→function channelDescriptor(type) {
 80→	var descs = getGon("channel_descriptors") || [];
 81→	return descs.find((d) => d.channel_type === channelType(type)) || null;
 82→}
 83→
 84→var MODE_LABELS = {
 85→	none: "Send only",
 86→	polling: "Polling",
 87→	gateway_loop: "Gateway",
 88→	socket_mode: "Socket Mode",
 89→	webhook: "Webhook",
 90→};
 91→
 92→var MODE_HINTS = {
 93→	webhook: "Requires a publicly reachable URL. Configure your platform to send events to the endpoint shown below.",
 94→	polling: "Connects automatically via long-polling. No public URL needed.",
 95→	gateway_loop: "Maintains a persistent connection. No public URL needed.",
 96→	socket_mode: "Connects via Socket Mode. No public URL needed.",
 97→	none: "This channel is send-only and cannot receive inbound messages.",
 98→};
 99→
100→function ConnectionModeHint({ type }) {
101→	var desc = channelDescriptor(type);
102→	if (!desc) return null;
103→	var hint = MODE_HINTS[desc.capabilities.inbound_mode];
104→	if (!hint) return null;
105→	return html`<div class="text-xs text-[var(--muted)] mt-1 flex items-center gap-1">
106→		<span class="tier-badge">${MODE_LABELS[desc.capabilities.inbound_mode]}</span>
107→		<span>${hint}</span>
108→	</div>`;
109→}
110→
111→function ChannelStorageNotice({ compact = false }) {
112→	return html`<div class="rounded-md border border-[var(--border)] bg-[var(--surface2)] px-3 py-2 text-xs text-[var(--muted)] ${compact ? "" : "max-w-3xl"}">
113→		<span class="font-medium text-[var(--text-strong)]">Storage note.</span> ${channelStorageNote()}
114→	</div>`;
115→}
116→
117→function prettyConfigJson(value) {
118→	try {
119→		return JSON.stringify(value || {}, null, 2);
120→	} catch (_error) {
121→		return "{}";
122→	}
123→}
124→
125→function copyToClipboard(value, successMessage) {
126→	var text = String(value || "").trim();
127→	if (!text) return;
128→	navigator.clipboard.writeText(text).then(() => showToast(successMessage));
129→}
130→
131→function MatrixInfoRow({ label, value, copyLabel = null }) {
132→	var text = String(value || "").trim();
133→	return html`<div class="flex items-center justify-between gap-3">
134→		<div class="min-w-0">
135→			<div class="text-[11px] uppercase tracking-wide text-emerald-200/70">${label}</div>
136→			<div class="truncate font-mono text-emerald-50">${text || "\u2014"}</div>
137→		</div>
138→		${
139→			text &&
140→			html`<button
141→				type="button"
142→				class="provider-btn provider-btn-sm provider-btn-secondary"
143→				onClick=${() => copyToClipboard(text, copyLabel || `${label} copied`)}>
144→				Copy
145→			</button>`
146→		}
147→	</div>`;
148→}
149→
150→function MatrixOwnershipCard({ channel, matrixStatus }) {
151→	var retryingOwnership = useSignal(false);
152→	var retryOwnershipError = useSignal("");
153→	var ownershipMode = normalizeMatrixOwnershipMode(matrixStatus?.ownership_mode);
154→	var authMode = normalizeMatrixAuthMode(matrixStatus?.auth_mode);
155→	var recoveryState = String(matrixStatus?.recovery_state || "unknown");
156→	var deviceVerified = !!matrixStatus?.device_verified_by_owner;
157→	var ownershipError = String(matrixStatus?.ownership_error || "").trim();
158→	var approvalMatch = ownershipError.match(/https?:\/\/\S+/);
159→	var ownershipIssue =
160→		ownershipMode !== "moltis_owned" || ownershipError.length === 0
161→			? "none"
162→			: ownershipError.includes("requires browser approval to reset cross-signing")
163→				? "approval_required"
164→				: ownershipError.includes("incomplete secret storage")
165→					? "incomplete_secret_storage"
166→					: "generic_blocked";
167→	var modeTitle =
168→		ownershipIssue === "approval_required"
169→			? "Ownership approval required"
170→			: ownershipIssue !== "none"
171→				? "Moltis ownership blocked"
172→				: ownershipMode === "moltis_owned"
173→					? "Managed by Moltis"
174→					: "User-managed in Element";
175→	var modeText =
176→		ownershipIssue === "approval_required"
177→			? "This existing Matrix account can already chat, but Matrix needs one browser approval before Moltis can take over encryption ownership. Open the approval page, approve the reset, then retry ownership setup."
178→			: ownershipIssue === "incomplete_secret_storage"
179→				? "This account already has partial Matrix secure-backup state. Finish or repair it in Element, or switch this channel to user-managed mode."
180→				: ownershipIssue === "generic_blocked"
181→					? "Moltis could not take ownership of this Matrix account automatically. Repair the account in Element or switch this channel to user-managed mode."
182→					: authMode === "password"
183→						? matrixOwnershipModeGuidance(authMode, ownershipMode)
184→						: "Access token auth is always user-managed. If you want encrypted Matrix chats, reconnect this channel with password auth so Moltis can create its own device.";
185→	var detailTitle =
186→		ownershipIssue === "approval_required"
187→			? "Browser approval pending"
188→			: ownershipError
189→				? "Ownership setup needs attention"
190→				: "";
191→	var detailText =
192→		ownershipIssue === "approval_required"
193→			? `Approve the reset while signed into ${matrixStatus?.user_id || "this Matrix account"} in the browser, then use the retry button here so Moltis can finish taking ownership.`
194→			: ownershipError;
195→	var approvalUrl = approvalMatch ? approvalMatch[0].replace(/[;),.]+$/, "") : "";
196→	var verificationText = deviceVerified ? "Device verified by owner" : "Device not yet verified by owner";
197→	var hasAccountDetails =
198→		!!String(channel.config?.homeserver || "").trim() ||
199→		!!String(matrixStatus?.user_id || "").trim() ||
200→		!!String(matrixStatus?.device_id || "").trim() ||
201→		!!String(matrixStatus?.device_display_name || channel.config?.device_display_name || "").trim();
202→
203→	function retryOwnershipSetup() {
204→		retryingOwnership.value = true;
205→		retryOwnershipError.value = "";
206→		sendRpc("channels.retry_ownership", {
207→			type: channelType(channel.type),
208→			account_id: channel.account_id,
209→		}).then((res) => {
210→			retryingOwnership.value = false;
211→			if (res?.ok) {
212→				showToast("Retrying Matrix ownership setup");
213→				loadChannels();
214→				return;
215→			}
216→			retryOwnershipError.value =
217→				(res?.error && (res.error.message || res.error.detail)) || "Failed to retry Matrix ownership setup.";
218→		});
219→	}
220→
221→	return html`<div class="rounded-md border border-sky-500/30 bg-sky-500/10 px-3 py-2 text-xs text-sky-100">
222→		<div class="flex items-center gap-2">
223→			<div class="font-medium text-sky-50">${modeTitle}</div>
224→			<span class="provider-item-badge ${deviceVerified ? "configured" : "oauth"}">${verificationText}</span>
225→		</div>
226→		<div class="mt-1 text-sky-100/90">${modeText}</div>
227→		<div class="mt-2 text-sky-100/90">
228→			Cross-signing: <span class="font-medium">${matrixStatus?.cross_signing_complete ? "ready" : "not ready"}</span>.
229→			Recovery: <span class="font-medium">${recoveryState}</span>.
230→		</div>
231→		${
232→			hasAccountDetails &&
233→			html`<details class="mt-2 rounded-md border border-sky-500/20 bg-sky-500/5 px-3 py-2">
234→				<summary class="cursor-pointer text-[11px] font-medium uppercase tracking-wide text-sky-100/80">
235→					Matrix account details
236→				</summary>
237→				<div class="mt-2 grid gap-2">
238→					<${MatrixInfoRow} label="Homeserver" value=${channel.config?.homeserver || ""} copyLabel="Homeserver copied" />
239→					<${MatrixInfoRow} label="Matrix user" value=${matrixStatus?.user_id || ""} copyLabel="Matrix user ID copied" />
240→					<${MatrixInfoRow} label="Device ID" value=${matrixStatus?.device_id || ""} copyLabel="Matrix device ID copied" />
