 91→    runtime: Arc<tokio::sync::RwLock<Option<NgrokRuntimeStatus>>>,
 92→    app: tokio::sync::RwLock<Option<Router>>,
 93→    active_tunnel: tokio::sync::Mutex<Option<NgrokActiveTunnel>>,
 94→}
 95→
