102→#[cfg(feature = "ngrok")]
103→impl NgrokController {
104→    fn new(
105→        gateway: Arc<GatewayState>,
106→        webauthn_registry: Option<SharedWebAuthnRegistry>,
107→        runtime: Arc<tokio::sync::RwLock<Option<NgrokRuntimeStatus>>>,
108→    ) -> Self {
109→        Self {
110→            inner: Arc::new(NgrokControllerInner {
111→                gateway,
112→                webauthn_registry,
113→                runtime,
114→                app: tokio::sync::RwLock::new(None),
115→                active_tunnel: tokio::sync::Mutex::new(None),
116→            }),
117→        }
118→    }
119→
120→    pub async fn configure_app(&self, app: Router) {
121→        let mut stored = self.inner.app.write().await;
122→        *stored = Some(app);
123→    }
124→
125→    pub async fn apply(
126→        &self,
127→        ngrok_config: &moltis_config::NgrokConfig,
128→    ) -> anyhow::Result<Option<NgrokRuntimeStatus>> {
129→        self.stop().await?;
130→
131→        if !ngrok_config.enabled {
132→            info!("ngrok tunnel disabled");
133→            return Ok(None);
134→        }
135→
136→        let active_tunnel = self.start(ngrok_config).await?;
137→        let status = active_tunnel.status.clone();
138→        {
139→            let mut runtime = self.inner.runtime.write().await;
140→            *runtime = Some(status.clone());
141→        }
142→        {
143→            let mut active = self.inner.active_tunnel.lock().await;
144→            *active = Some(active_tunnel);
145→        }
146→        info!(url = %status.public_url, "ngrok tunnel started");
147→        Ok(Some(status))
148→    }
149→
150→    async fn start(
151→        &self,
152→        ngrok_config: &moltis_config::NgrokConfig,
153→    ) -> anyhow::Result<NgrokActiveTunnel> {
154→        let app = {
155→            let stored = self.inner.app.read().await;
156→            stored.clone().ok_or_else(|| {
157→                anyhow::anyhow!("ngrok tunnel cannot start before the HTTP app is ready")
158→            })?
159→        };
160→
161→        start_ngrok_tunnel(
162→            app,
163→            Arc::clone(&self.inner.gateway),
164→            self.inner.webauthn_registry.clone(),
165→            ngrok_config,
166→        )
167→        .await
168→    }
169→
170→    pub async fn stop(&self) -> anyhow::Result<()> {
171→        use ngrok::prelude::TunnelCloser;
172→
173→        let active_tunnel = {
174→            let mut active = self.inner.active_tunnel.lock().await;
175→            active.take()
176→        };
177→
178→        let Some(mut active_tunnel) = active_tunnel else {
179→            let mut runtime = self.inner.runtime.write().await;
180→            *runtime = None;
181→            return Ok(());
182→        };
183→
184→        let stopped_url = active_tunnel.status.public_url.clone();
185→        active_tunnel.loopback_shutdown.cancel();
186→
187→        if let Err(error) = active_tunnel.forwarder.close().await {
188→            warn!(url = %stopped_url, %error, "failed to close ngrok tunnel");
189→        }
190→        if let Err(error) = active_tunnel.session.close().await {
191→            warn!(url = %stopped_url, %error, "failed to close ngrok session");
192→        }
193→
194→        match active_tunnel.forwarder.join().await {
195→            Ok(Ok(())) => {},
196→            Ok(Err(error)) => {
197→                warn!(url = %stopped_url, %error, "ngrok tunnel forwarder exited with error");
198→            },
199→            Err(error) => {
200→                warn!(url = %stopped_url, %error, "ngrok tunnel join failed");
201→            },
202→        }
203→
204→        match active_tunnel.loopback_task.await {
205→            Ok(()) => {},
206→            Err(error) => {
207→                warn!(url = %stopped_url, %error, "ngrok loopback server task join failed");
208→            },
209→        }
210→
211→        let mut runtime = self.inner.runtime.write().await;
212→        *runtime = None;
213→        info!(url = %stopped_url, "ngrok tunnel stopped");
214→        Ok(())
215→    }
216→}
