226→#[cfg(feature = "mdns")]
227→fn instance_slug(config: &moltis_config::MoltisConfig) -> String {
228→    let mut raw_name = config.identity.name.clone();
229→    if let Some(file_identity) = moltis_config::load_identity()
230→        && file_identity.name.is_some()
231→    {
232→        raw_name = file_identity.name;
233→    }
234→
235→    let base = raw_name
236→        .unwrap_or_else(|| "moltis".to_string())
237→        .to_lowercase();
238→    let mut out = String::new();
239→    let mut last_dash = false;
240→    for ch in base.chars() {
241→        let mapped = if ch.is_ascii_alphanumeric() {
242→            ch
243→        } else {
244→            '-'
245→        };
246→        if mapped == '-' {
247→            if !last_dash {
248→                out.push(mapped);
249→            }
250→            last_dash = true;
251→        } else {
252→            out.push(mapped);
253→            last_dash = false;
254→        }
255→    }
256→    let out = out.trim_matches('-').to_string();
257→    if out.is_empty() {
258→        "moltis".to_string()
259→    } else {
260→        out
261→    }
262→}
