 96→/// Memory snapshot included in gon data and tick broadcasts.
 97→#[derive(serde::Serialize)]
 98→#[serde(rename_all = "camelCase")]
 99→pub(crate) struct MemSnapshot {
100→    process: u64,
101→    #[serde(skip_serializing_if = "Option::is_none")]
102→    local_llama_cpp: Option<u64>,
103→    available: u64,
104→    total: u64,
105→}
106→
107→/// Collect a point-in-time memory snapshot (process RSS + local llama.cpp +
108→/// system memory).
109→pub(crate) fn collect_mem_snapshot() -> MemSnapshot {
110→    let mut sys = sysinfo::System::new();
111→    sys.refresh_memory();
112→    let pid = sysinfo::get_current_pid().ok();
113→    if let Some(pid) = pid {
114→        sys.refresh_processes_specifics(
115→            sysinfo::ProcessesToUpdate::Some(&[pid]),
116→            false,
117→            sysinfo::ProcessRefreshKind::nothing().with_memory(),
118→        );
119→    }
120→    let process = pid
121→        .and_then(|p| sys.process(p))
122→        .map(|p| p.memory())
123→        .unwrap_or(0);
124→    let local_llama_cpp = moltis_gateway::server::local_llama_cpp_bytes_for_ui();
125→    let total = sys.total_memory();
126→    // available_memory() returns 0 on macOS; fall back to total − used.
127→    let available = match sys.available_memory() {
128→        0 => total.saturating_sub(sys.used_memory()),
129→        v => v,
130→    };
131→    MemSnapshot {
132→        process,
133→        local_llama_cpp: (local_llama_cpp > 0).then_some(local_llama_cpp),
134→        available,
135→        total,
136→    }
137→}
