141→fn detect_git_branch() -> Option<String> {
142→    static BRANCH: std::sync::OnceLock<Option<String>> = std::sync::OnceLock::new();
143→    BRANCH
144→        .get_or_init(|| {
145→            let repo = gix::discover(".").ok()?;
146→            let head = repo.head().ok()?;
147→            let branch = head.referent_name()?.shorten().to_string();
148→            parse_git_branch(&branch)
149→        })
150→        .clone()
151→}
152→
153→fn parse_git_branch(raw: &str) -> Option<String> {
154→    let branch = raw.trim();
155→    if branch.is_empty() || branch == "main" || branch == "master" {
156→        None
157→    } else {
158→        Some(branch.to_owned())
159→    }
160→}
