162→const SESSION_PREVIEW_MAX_CHARS: usize = 200;
163→
164→fn truncate_preview(text: &str, max_chars: usize) -> String {
165→    let mut chars = text.chars();
166→    let mut out = String::new();
167→    for _ in 0..max_chars {
168→        if let Some(ch) = chars.next() {
169→            out.push(ch);
170→        } else {
171→            return out;
172→        }
173→    }
174→    if chars.next().is_some() {
175→        out.push('…');
176→    }
177→    out
178→}
