180→async fn build_recent_sessions_snapshot(gw: &GatewayState, limit: usize) -> Vec<serde_json::Value> {
181→    let Some(ref metadata) = gw.services.session_metadata else {
182→        return Vec::new();
183→    };
184→
185→    let mut recent = Vec::new();
186→    for entry in metadata.list().await.into_iter().take(limit) {
187→        let active_channel = if let Some(ref binding_json) = entry.channel_binding {
188→            if let Ok(target) =
189→                serde_json::from_str::<moltis_channels::ChannelReplyTarget>(binding_json)
190→            {
191→                metadata
192→                    .get_active_session(
193→                        target.channel_type.as_str(),
194→                        &target.account_id,
195→                        &target.chat_id,
196→                        target.thread_id.as_deref(),
197→                    )
198→                    .await
199→                    .map(|key| key == entry.key)
200→                    .unwrap_or(false)
201→            } else {
202→                false
203→            }
204→        } else {
205→            false
206→        };
207→        let preview = entry
208→            .preview
209→            .as_deref()
210→            .map(|text| truncate_preview(text, SESSION_PREVIEW_MAX_CHARS));
211→        let agent_id = entry.agent_id.clone().unwrap_or_else(|| "main".to_owned());
212→        let agent_id_camel = agent_id.clone();
213→
214→        recent.push(serde_json::json!({
215→            "id": entry.id,
216→            "key": entry.key,
217→            "label": entry.label,
218→            "model": entry.model,
219→            "createdAt": entry.created_at,
220→            "updatedAt": entry.updated_at,
221→            "messageCount": entry.message_count,
222→            "lastSeenMessageCount": entry.last_seen_message_count,
223→            "projectId": entry.project_id,
224→            "sandbox_enabled": entry.sandbox_enabled,
225→            "sandbox_image": entry.sandbox_image,
226→            "worktree_branch": entry.worktree_branch,
227→            "channelBinding": entry.channel_binding,
228→            "activeChannel": active_channel,
229→            "parentSessionKey": entry.parent_session_key,
230→            "forkPoint": entry.fork_point,
231→            "mcpDisabled": entry.mcp_disabled,
232→            "preview": preview,
233→            "archived": entry.archived,
234→            "agent_id": agent_id,
235→            "agentId": agent_id_camel,
236→            "node_id": entry.node_id,
237→            "version": entry.version,
238→        }));
239→    }
240→
241→    recent
242→}
