257→pub(crate) async fn build_nav_counts(gw: &GatewayState) -> NavCounts {
258→    let (projects, models, channels, mcp, crons) = tokio::join!(
259→        gw.services.project.list(),
260→        gw.services.model.list(),
261→        gw.services.channel.status(),
262→        gw.services.mcp.list(),
263→        gw.services.cron.list(),
264→    );
265→
266→    let projects = projects
267→        .ok()
268→        .and_then(|v| v.as_array().map(|a| a.len()))
269→        .unwrap_or(0);
270→
271→    let providers = models
272→        .ok()
273→        .and_then(|v| {
274→            v.as_array().map(|arr| {
275→                let mut names: HashSet<&str> = HashSet::new();
276→                for m in arr {
277→                    if let Some(p) = m.get("provider").and_then(|p| p.as_str()) {
278→                        names.insert(p);
279→                    }
280→                }
281→                names.len()
282→            })
283→        })
284→        .unwrap_or(0);
285→
286→    let channels = channels
287→        .ok()
288→        .and_then(|v| {
289→            v.get("channels")
290→                .and_then(|c| c.as_array())
291→                .map(|a| a.len())
292→        })
293→        .unwrap_or(0);
294→
295→    let mut skills = 0usize;
296→    if let Ok(path) = moltis_skills::manifest::ManifestStore::default_path() {
297→        let store = moltis_skills::manifest::ManifestStore::new(path);
298→        if let Ok(m) = store.load() {
299→            skills = m
300→                .repos
301→                .iter()
302→                .flat_map(|r| &r.skills)
303→                .filter(|s| s.enabled)
304→                .count();
305→        }
306→    }
307→
308→    let mcp = mcp
309→        .ok()
310→        .and_then(|v| {
311→            v.as_array().map(|arr| {
312→                arr.iter()
313→                    .filter(|s| s.get("state").and_then(|s| s.as_str()) == Some("running"))
314→                    .count()
315→            })
316→        })
317→        .unwrap_or(0);
318→
319→    let crons = crons
320→        .ok()
321→        .and_then(|v| {
322→            v.as_array().map(|arr| {
323→                arr.iter()
324→                    .filter(|j| {
325→                        let enabled = j.get("enabled").and_then(|e| e.as_bool()).unwrap_or(false);
326→                        let system = j.get("system").and_then(|s| s.as_bool()).unwrap_or(false);
327→                        enabled && !system
328→                    })
329→                    .count()
330→            })
331→        })
332→        .unwrap_or(0);
333→
334→    let hooks = gw.inner.read().await.discovered_hooks.len();
335→
336→    NavCounts {
337→        projects,
338→        providers,
339→        channels,
340→        skills,
341→        mcp,
342→        crons,
343→        hooks,
344→    }
345→}
