349→pub(crate) async fn build_gon_data(gw: &GatewayState) -> GonData {
350→    const GON_SESSIONS_RECENT_LIMIT: usize = 30;
351→
352→    let port = gw.port;
353→    let identity = gw
354→        .services
355→        .onboarding
356→        .identity_get()
357→        .await
358→        .ok()
359→        .and_then(|v| serde_json::from_value(v).ok())
360→        .unwrap_or_default();
361→
362→    let counts = build_nav_counts(gw).await;
363→    let (crons, cron_status) = tokio::join!(gw.services.cron.list(), gw.services.cron.status());
364→    let crons: Vec<moltis_cron::types::CronJob> = crons
365→        .ok()
366→        .and_then(|v| serde_json::from_value(v).ok())
367→        .unwrap_or_default();
368→    let cron_status: moltis_cron::types::CronStatus = cron_status
369→        .ok()
370→        .and_then(|v| serde_json::from_value(v).ok())
371→        .unwrap_or_default();
372→    let (heartbeat_config, cached_channels_offered) = {
373→        let inner = gw.inner.read().await;
374→        (
375→            inner.heartbeat_config.clone(),
376→            inner.channels_offered.clone(),
377→        )
378→    };
379→    let channels_offered = resolve_channels_offered(cached_channels_offered);
380→    let channel_descriptors: Vec<moltis_channels::ChannelDescriptor> = channels_offered
381→        .iter()
382→        .filter_map(|s| s.parse::<moltis_channels::ChannelType>().ok())
383→        .map(|ct| ct.descriptor())
384→        .collect();
385→
386→    let heartbeat_runs: Vec<moltis_cron::types::CronRunRecord> = gw
387→        .services
388→        .cron
389→        .runs(serde_json::json!({ "id": "__heartbeat__", "limit": 10 }))
390→        .await
391→        .ok()
392→        .and_then(|v| serde_json::from_value(v).ok())
393→        .unwrap_or_default();
394→
395→    let sandbox = if let Some(ref router) = gw.sandbox_router {
396→        SandboxGonInfo {
397→            backend: router.backend_name().to_owned(),
398→            os: std::env::consts::OS,
399→            default_image: router.default_image().await,
400→            image_building: router
401→                .building_flag
402→                .load(std::sync::atomic::Ordering::Relaxed),
403→        }
404→    } else {
405→        SandboxGonInfo {
406→            backend: "none".to_owned(),
407→            os: std::env::consts::OS,
408→            default_image: moltis_tools::sandbox::DEFAULT_SANDBOX_IMAGE.to_owned(),
409→            image_building: false,
410→        }
411→    };
412→
413→    // Fetch agent personas for the gon data.
414→    let agents: Vec<serde_json::Value> = if let Some(ref store) = gw.services.agent_persona_store {
415→        store
416→            .list()
417→            .await
418→            .ok()
419→            .map(|list| {
420→                list.into_iter()
421→                    .map(|a| serde_json::to_value(a).unwrap_or_default())
422→                    .collect()
423→            })
424→            .unwrap_or_default()
425→    } else {
426→        Vec::new()
427→    };
428→
429→    let sessions_recent = build_recent_sessions_snapshot(gw, GON_SESSIONS_RECENT_LIMIT).await;
430→
431→    GonData {
432→        identity,
433→        version: gw.version.clone(),
434→        port,
435→        counts,
436→        crons,
437→        cron_status,
438→        heartbeat_config,
439→        heartbeat_runs,
440→        voice_enabled: cfg!(feature = "voice"),
441→        graphql_enabled: cfg!(feature = "graphql"),
442→        git_branch: detect_git_branch(),
443→        mem: collect_mem_snapshot(),
444→        deploy_platform: gw.deploy_platform.clone(),
445→        channels_offered,
446→        channel_descriptors,
447→        channel_storage_db_path: moltis_config::data_dir()
448→            .join("moltis.db")
449→            .display()
450→            .to_string(),
451→        update: gw.inner.read().await.update.clone(),
452→        sandbox,
453→        routes: SPA_ROUTES.clone(),
454→        started_at: *PROCESS_STARTED_AT_MS,
455→        openclaw_detected: moltis_gateway::server::openclaw_detected_for_ui(),
456→        sessions_recent,
457→        agents,
458→        #[cfg(feature = "vault")]
459→        vault_status: {
460→            if let Some(ref vault) = gw.vault {
461→                match vault.status().await {
462→                    Ok(s) => format!("{s:?}").to_lowercase(),
463→                    Err(_) => "error".to_owned(),
464→                }
465→            } else {
466→                "disabled".to_owned()
467→            }
468→        },
469→    }
470→}
