472→fn load_channels_offered_from_config_path(
473→    path: &Path,
474→) -> Result<Vec<String>, moltis_config::Error> {
475→    moltis_config::loader::load_config(path).map(|config| config.channels.offered)
476→}
477→
478→fn resolve_channels_offered(cached_channels_offered: Vec<String>) -> Vec<String> {
479→    let Some(path) = moltis_config::loader::find_config_file() else {
480→        return cached_channels_offered;
481→    };
482→
483→    match load_channels_offered_from_config_path(&path) {
484→        Ok(channels_offered) => channels_offered,
485→        Err(error) => {
486→            warn!(
487→                path = %path.display(),
488→                error = %error,
489→                "failed to reload channels.offered for gon data, using startup value"
490→            );
491→            cached_channels_offered
492→        },
493→    }
494→}
